#include <iostream>
using namespace std;

template <typename T, int SIZE>
class Stack {
private:
    T data[SIZE];
    int top;

public:
    Stack() : top(-1) {}

    void push(T value) {
        if (top < SIZE - 1) {
            data[++top] = value;
        }
    }

    T pop() {
        if (top >= 0) {
            return data[top--];
        }
        return T();
    }

    bool isEmpty() {
        return top == -1;
    }
};

int main() {
    Stack<int, 5> intStack;

    intStack.push(10);
    intStack.push(20);
    intStack.push(30);

    cout << \Элементы стека: ";
    while (!intStack.isEmpty()) {
        cout << intStack.pop() << " ";
    }
    cout << endl;

    return 0;
}"

