#include <iostream>
#include <memory>
using namespace std;

class Resource {
public:
    Resource() { cout << \Ресурс создан" << endl; }
    ~Resource() { cout << "Ресурс уничтожен" << endl; }
    void use() { cout << "Ресурс используется" << endl; }
};

int main() {
    unique_ptr<Resource> res1(new Resource());
    res1->use();

    unique_ptr<Resource> res2 = move(res1);
    if (!res1) {
        cout << "res1 теперь пуст" << endl;
    }
    res2->use();

    return 0;
}"

