#include <iostream>
#include <memory>
#include <string>
using namespace std;

class Shape {
public:
    virtual void draw() = 0;
    virtual ~Shape() = default;

    static unique_ptr<Shape> create(const string& type);
};

class Circle : public Shape {
public:
    void draw() override {
        cout << \Рисую круг" << endl;
    }
};

class Rectangle : public Shape {
public:
    void draw() override {
        cout << "Рисую прямоугольник" << endl;
    }
};

