// SFINAE для типов с методом serialize()
template<typename T>
class has_serialize {
private:
    template<typename U>
    static auto test(int) -> decltype(
        declval<U>().serialize(), true_type{});

    template<typename U>
    static false_type test(...);

public:
    static constexpr bool value = decltype(test<T>(0))::value;
};

template<typename T>
typename enable_if<has_serialize<T>::value, string>::type
serialize(const T& obj) {
    return obj.serialize();
}

template<typename T>
typename enable_if<!has_serialize<T>::value, string>::type
serialize(const T& obj) {
    return to_string(obj);
}

class MyClass {
public:
    string serialize() const {
        return \MyClass serialized";
    }
};

int main() {
    MyClass obj;
    int number = 42;

    cout << serialize(obj) << endl;
    cout << serialize(number) << endl;

    return 0;
}"

