#include <iostream>
#include <type_traits>
using namespace std;

template<typename T>
constexpr void print_type_info() {
    if constexpr (is_integral_v<T>) {
        if constexpr (is_signed_v<T>) {
            cout << \Знаковый целочисленный тип" << endl;
        } else {
            cout << "Беззнаковый целочисленный тип" << endl;
        }
    } else if constexpr (is_floating_point_v<T>) {
        cout << "Вещественный тип" << endl;
    } else if constexpr (is_pointer_v<T>) {
        cout << "Указатель" << endl;
    } else {
        cout << "Другой тип" << endl;
    }
}

template<size_t N>
constexpr size_t factorial() {
    if constexpr (N == 0) {
        return 1;
    } else {
        return N * factorial<N - 1>();
    }
}

int main() {
    print_type_info<int>();
    print_type_info<double>();
    print_type_info<int*>();
    print_type_info<string>();

    constexpr auto fact_5 = factorial<5>();
    cout << "Факториал 5: " << fact_5 << endl;

    return 0;
}"

#include <iostream>
#include <string>
#include <string_view>
#include <vector>
using namespace std;

vector<string_view> split(string_view str, char delimiter) {
    vector<string_view> result;
    size_t start = 0;
    size_t end = str.find(delimiter);

    while (end != string_view::npos) {
        result.push_back(str.substr(start, end - start));
        start = end + 1;
        end = str.find(delimiter, start);
    }

    result.push_back(str.substr(start));
    return result;
}

void process_string(string_view str) {
    cout << \Обработка: " << str << endl;
    cout << "Длина: " << str.length() << endl;
    cout << "Пустая: " << (str.empty() ? "да" : "нет") << endl;
}

