template<typename T>
class Stack {
private:
    vector<T> data;
public:
    void push(const T& value) {
        data.push_back(value);
    }

    void pop() {
        if (empty()) {
            throw runtime_error(\Стек пуст");
        }
        data.pop_back();
    }

    T& top() {
        if (empty()) {
            throw runtime_error("Стек пуст");
        }
        return data.back();
    }

    bool empty() const {
        return data.empty();
    }

    size_t size() const {
        return data.size();
    }
};

int main() {
