    stack.pop();
    cout << "После удаления: " << stack.top() << endl;
    return 0;
}"

#include <iostream>
#include <cmath>
using namespace std;

double f(double x) {
    return x * x;  // функция x^2
}

double integrate(double a, double b, int n) {
    double h = (b - a) / n;
    double sum = 0.0;

    for (int i = 0; i < n; i++) {
        double x = a + (i + 0.5) * h;
        sum += f(x);
    }

    return sum * h;
}

int main() {
    double a = 0.0, b = 2.0;
    int n = 1000;

    double result = integrate(a, b, n);
    cout << \Интеграл от " << a << " до " << b << " = " << result << endl;
    cout << "Точное значение: " << (b*b*b - a*a*a)/3.0 << endl;
    return 0;
}"

#include <iostream>
#include <vector>
#include <queue>
#include <limits>
#include <utility>
using namespace std;

const int INF = numeric_limits<int>::max();

vector<int> dijkstra(const vector<vector<pair<int, int>>>& graph, int start) {
    int n = graph.size();
    vector<int> dist(n, INF);
    dist[start] = 0;

    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    pq.push({0, start});

    while (!pq.empty()) {
        int current_dist = pq.top().first;
        int u = pq.top().second;
        pq.pop();

        if (current_dist > dist[u]) continue;

        for (const auto& edge : graph[u]) {
            int v = edge.first;
            int weight = edge.second;

            if (dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                pq.push({dist[v], v});
            }
        }
    }

    return dist;
}

int main() {
    int n = 5;
    vector<vector<pair<int, int>>> graph(n);

    graph[0].push_back({1, 4});
    graph[0].push_back({2, 1});
    graph[1].push_back({3, 1});
    graph[2].push_back({1, 2});
    graph[2].push_back({3, 5});
    graph[3].push_back({4, 3});

    vector<int> distances = dijkstra(graph, 0);

    cout << \Кратчайшие расстояния от вершины 0:" << endl;
    for (int i = 0; i < n; i++) {
        cout << "До " << i << ": " << distances[i] << endl;
    }
    return 0;
}"

