#include <iostream>
#include <thread>
#include <atomic>
#include <vector>
#include <chrono>
using namespace std;

class Counter {
private:
    atomic<int> value{0};
public:
    void increment() {
        value.fetch_add(1, memory_order_relaxed);
    }

    void decrement() {
        value.fetch_sub(1, memory_order_relaxed);
    }

    int get() const {
        return value.load(memory_order_relaxed);
    }
};

void worker(Counter& counter, int iterations) {
    for (int i = 0; i < iterations; i++) {
        counter.increment();
        this_thread::sleep_for(chrono::microseconds(1));
    }
}

int main() {
    Counter counter;
    vector<thread> threads;
    const int num_threads = 10;
    const int iterations_per_thread = 100;

    // Запускаем потоки
