#include <iostream>
#include <memory>
using namespace std;

enum class Color { RED, BLACK };

template<typename T>
class RBTree {
private:
    struct Node {
        T data;
        Color color;
        shared_ptr<Node> left, right, parent;

        Node(T val) : data(val), color(Color::RED), 
                     left(nullptr), right(nullptr), parent(nullptr) {}
    };

    shared_ptr<Node> root;

    void rotateLeft(shared_ptr<Node> x) {
        auto y = x->right;
        x->right = y->left;

        if (y->left != nullptr) {
            y->left->parent = x;
        }

        y->parent = x->parent;

        if (x->parent == nullptr) {
            root = y;
        } else if (x == x->parent->left) {
            x->parent->left = y;
        } else {
            x->parent->right = y;
        }

        y->left = x;
        x->parent = y;
    }

    void rotateRight(shared_ptr<Node> x) {
        auto y = x->left;
        x->left = y->right;

        if (y->right != nullptr) {
            y->right->parent = x;
        }

        y->parent = x->parent;

        if (x->parent == nullptr) {
            root = y;
        } else if (x == x->parent->right) {
            x->parent->right = y;
        } else {
            x->parent->left = y;
        }

        y->right = x;
        x->parent = y;
    }

    void fixInsert(shared_ptr<Node> k) {
        shared_ptr<Node> u;
        while (k->parent != nullptr && k->parent->color == Color::RED) {
            if (k->parent == k->parent->parent->right) {
                u = k->parent->parent->left;
                if (u != nullptr && u->color == Color::RED) {
                    u->color = Color::BLACK;
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    k = k->parent->parent;
                } else {
                    if (k == k->parent->left) {
                        k = k->parent;
                        rotateRight(k);
                    }
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    rotateLeft(k->parent->parent);
                }
            } else {
                u = k->parent->parent->right;
                if (u != nullptr && u->color == Color::RED) {
                    u->color = Color::BLACK;
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    k = k->parent->parent;
                } else {
                    if (k == k->parent->right) {
                        k = k->parent;
                        rotateLeft(k);
                    }
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    rotateRight(k->parent->parent);
                }
            }
            if (k == root) break;
        }
        root->color = Color::BLACK;
    }

    void inorderHelper(shared_ptr<Node> node) {
        if (node != nullptr) {
            inorderHelper(node->left);
            cout << node->data << \(" << (node->color == Color::RED ? "R" : "B") << ") ";
            inorderHelper(node->right);
        }
    }

public:
    RBTree() : root(nullptr) {}

    void insert(T val) {
        auto node = make_shared<Node>(val);

        shared_ptr<Node> y = nullptr;
        auto x = root;

        while (x != nullptr) {
            y = x;
            if (node->data < x->data) {
                x = x->left;
            } else {
                x = x->right;
            }
        }

        node->parent = y;

        if (y == nullptr) {
            root = node;
        } else if (node->data < y->data) {
            y->left = node;
        } else {
            y->right = node;
        }

        if (node->parent == nullptr) {
            node->color = Color::BLACK;
            return;
        }

        if (node->parent->parent == nullptr) {
            return;
        }

        fixInsert(node);
    }

    void printInorder() {
        inorderHelper(root);
        cout << endl;
    }

    bool search(T val) {
        auto current = root;
        while (current != nullptr) {
            if (val == current->data) {
                return true;
            } else if (val < current->data) {
                current = current->left;
            } else {
                current = current->right;
            }
        }
        return false;
    }
};

int main() {
    RBTree<int> tree;

    tree.insert(10);
    tree.insert(20);
    tree.insert(30);
    tree.insert(15);
    tree.insert(25);
    tree.insert(5);
    tree.insert(35);

    cout << "Обход красно-черного дерева: ";
    tree.printInorder();

    cout << "Поиск 25: " << (tree.search(25) ? "Найдено" : "Не найдено") << endl;
    cout << "Поиск 40: " << (tree.search(40) ? "Найдено" : "Не найдено") << endl;

    return 0;
}"

#include <iostream>
#include <vector>
#include <string>
#include <map>
#include <bitset>
using namespace std;

class LZWCompressor {
private:
    map<string, int> dictionary;
    int dict_size;

public:
    LZWCompressor() {
        // Инициализация словаря с ASCII символами
        for (int i = 0; i < 256; i++) {
            dictionary[string(1, static_cast<char>(i))] = i;
        }
        dict_size = 256;
    }

    vector<int> compress(const string& input) {
        string w;
        vector<int> result;

        for (char c : input) {
            string wc = w + c;
            if (dictionary.find(wc) != dictionary.end()) {
                w = wc;
            } else {
                result.push_back(dictionary[w]);
                dictionary[wc] = dict_size++;
                w = string(1, c);
            }
        }

        if (!w.empty()) {
            result.push_back(dictionary[w]);
        }

        return result;
    }

    string decompress(const vector<int>& compressed) {
        map<int, string> dictionary;

        // Инициализация словаря с ASCII символами
        for (int i = 0; i < 256; i++) {
            dictionary[i] = string(1, static_cast<char>(i));
        }

        int dict_size = 256;
        string w(1, static_cast<char>(compressed[0]));
        string result = w;

        for (size_t i = 1; i < compressed.size(); i++) {
            int k = compressed[i];
            string entry;

            if (dictionary.find(k) != dictionary.end()) {
                entry = dictionary[k];
            } else if (k == dict_size) {
                entry = w + w[0];
            } else {
                throw runtime_error(\Ошибка декомпрессии: неверный код");
            }

            result += entry;
            dictionary[dict_size++] = w + entry[0];
            w = entry;
        }

        return result;
    }
};

int main() {
    LZWCompressor lzw;
    string input;

    cout << "Введите строку для сжатия: ";
    getline(cin

column3:
 input);

    auto compressed = lzw.compress(input);

    cout << "Сжатые коды: ";
    for (int code : compressed) {
        cout << code << " ";
    }
    cout << endl;

    cout << "Коэффициент сжатия: " 
         << (static_cast<double>(input.length()) / compressed.size()) << endl;

    string decompressed = lzw.decompress(compressed);
    cout << "Расжатая строка: " << decompressed << endl;

    cout << "Совпадение: " << (input == decompressed ? "Да" : "Нет") << endl;

    return 0;
}"

