string generateUUID() {
    random_device rd;
    mt19937 gen(rd());
    uniform_int_distribution<> dis(0, 15);

    stringstream ss;
    ss << hex;
    for(int i = 0; i < 32; i++) {
        if(i == 8 || i == 12 || i == 16 || i == 20) ss << \-";
        ss << dis(gen);
    }
    return ss.str();
}

