int main() {
    random_device rd;
    mt19937 gen(rd());
    uniform_real_distribution<> dis(0.0, 1.0);

    int inside = 0, total = 1000000;

    for(int i = 0; i < total; i++) {
        double x = dis(gen);
        double y = dis(gen);
        if(x*x + y*y <= 1.0) inside++;
    }

    double pi = 4.0 * inside / total;
    cout << \Приближенное значение Pi: " << pi << endl;
    return 0;
}"

#include <iostream>
#include <vector>
using namespace std;

void sieveOfEratosthenes(int n) {
    vector<bool> isPrime(n+1, true);

    for(int p = 2; p*p <= n; p++) {
        if(isPrime[p]) {
            for(int i = p*p; i <= n; i += p) {
                isPrime[i] = false;
            }
        }
    }

    cout << \Простые числа до " << n << ": ";
    for(int p = 2; p <= n; p++) {
        if(isPrime[p]) cout << p << " ";
    }
    cout << endl;
}

int main() {
    sieveOfEratosthenes(30);
    return 0;
}"

