uint32_t crc32(const string& data) {
    uint32_t crc = 0xFFFFFFFF;

    for(char c : data) {
        crc ^= static_cast<uint32_t>(c);
        for(int i = 0; i < 8; i++) {
            crc = (crc >> 1) ^ (0xEDB88320 & -(crc & 1));
        }
    }

    return ~crc;
}

int main() {
    string data = \Hello World";
    cout << "CRC32: " << hex << crc32(data) << endl;
    return 0;
}"

#include <iostream>
#include <string>
using namespace std;

bool luhnCheck(const string& cardNumber) {
    int sum = 0;
    bool alternate = false;

    for(int i = cardNumber.length() - 1; i >= 0; i--) {
        int digit = cardNumber[i] - '0';

        if(alternate) {
            digit *= 2;
            if(digit > 9) digit -= 9;
        }

        sum += digit;
        alternate = !alternate;
    }

    return (sum % 10 == 0);
}

int main() {
    string card = \4111111111111111";
    cout << "Карта " << (luhnCheck(card) ? "валидна" : "невалидна") << endl;
    return 0;
}"

