string caesarCipher(const string& text, int shift) {
    string result;

    for(char c : text) {
        if(isalpha(c)) {
            char base = isupper(c) ? 'A' : 'a';
            result += (c - base + shift) % 26 + base;
        } else {
            result += c;
        }
    }

    return result;
}

