#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    vector<int> numbers = {5, 2, 8, 1, 9};

    // Сортировка с лямбдой
    sort(numbers.begin(), numbers.end(), [](int a, int b) {
        return a < b;
    });

    cout << \Отсортированный вектор: ";
    for(int num : numbers) {
        cout << num << " ";
    }
    cout << endl;
    return 0;
}"

