#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<int> vec = {1, 2, 3};

    vec.push_back(4); // добавление
    vec.pop_back();   // удаление последнего

    cout << \Элементы: ";
    for(int num : vec) {
        cout << num << " ";
    }
    cout << "\nРазмер: " << vec.size() << endl;
    return 0;
}"

#include <iostream>
#include <map>
using namespace std;

int main() {
    map<string, int> ages;

    ages[\Анна"] = 25;
    ages["Петр"] = 30;
    ages["Мария"] = 28;

    for(auto& pair : ages) {
        cout << pair.first << ": " << pair.second << " лет" << endl;
    }
    return 0;
}"

#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    vector<int> numbers = {5, 2, 8, 1, 9, 3};

    sort(numbers.begin(), numbers.end());
    auto it = find(numbers.begin(), numbers.end(), 8);

    if(it != numbers.end()) {
        cout << \Найдено: " << *it << endl;
    }

    cout << "Отсортированный вектор: ";
    for(int num : numbers) {
        cout << num << " ";
    }
    cout << endl;
    return 0;
}"

