#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<int> vec1 = {1, 2, 3, 4, 5};

    cout << \До move:" << endl;
    cout << "vec1 размер: " << vec1.size() << endl;

    vector<int> vec2 = move(vec1);

    cout << "После move:" << endl;
    cout << "vec1 размер: " << vec1.size() << endl;
    cout << "vec2 размер: " << vec2.size() << endl;

    return 0;
}"

#include <iostream>
using namespace std;

constexpr int square(int x) {
    return x * x;
}

int main() {
    constexpr int result = square(5);
    cout << \Квадрат 5: " << result << endl;

    int arr[square(3)]; // массив размером 9
    cout << "Размер массива: " << sizeof(arr)/sizeof(arr[0]) << endl;

    return 0;
}"

